 1	import type { FC } from 'react';
 2	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 3	import useProviderInventory from 'src/modules/Providers/hooks/useProviderInventory';
 4	import { PageHeadings } from 'src/modules/Providers/utils/components/DetailsPage/PageHeadings';
 5	import type { ProviderData } from 'src/modules/Providers/utils/types/ProviderData';
 6	import ProviderActionsDropdown from 'src/providers/actions/ProviderActionsDropdown';
 7	
 8	import { type ProviderInventory, ProviderModel } from '@kubev2v/types';
 9	import { Split, SplitItem } from '@patternfly/react-core';
10	
11	import CreatePlanAction from './components/CreatePlanAction';
12	import ProviderPageHeaderAlerts from './components/ProviderPageHeaderAlerts';
13	import { useProvider } from './hooks/useProvider';
14	import type { ProviderDetailsPageProps } from './utils/types';
15	
16	const ProviderPageHeader: FC<ProviderDetailsPageProps> = ({ name, namespace }) => {
17	  const { provider } = useProvider(name, namespace);
18	  const {
19	    error: inventoryError,
20	    inventory,
21	    loading: inventoryLoading,
22	  } = useProviderInventory<ProviderInventory>({
23	    provider,
24	  });
25	  const permissions = useGetDeleteAndEditAccessReview({ model: ProviderModel, namespace });
26	  const data: ProviderData = { inventory: inventory ?? undefined, permissions, provider };
27	
28	  return (
29	    <PageHeadings
30	      model={ProviderModel}
31	      obj={provider}
32	      namespace={namespace}
33	      testId="resource-details-title"
34	      actions={
35	        <Split hasGutter>
36	          <SplitItem>
37	            <CreatePlanAction namespace={namespace} provider={provider} />
38	          </SplitItem>
39	
40	          <SplitItem>
41	            <ProviderActionsDropdown data={data} />
42	          </SplitItem>
43	        </Split>
44	      }
45	    >
46	      <ProviderPageHeaderAlerts
47	        provider={provider}
48	        inventoryLoading={inventoryLoading}
49	        inventoryError={inventoryError}
50	      />
51	    </PageHeadings>
52	  );
53	};
54	
55	export default ProviderPageHeader;

